class DetectionEngine:
    """Moteur de détection combinant règles et TIP."""

    def __init__(self, ioc_db: Dict, config: Dict):
        self.ioc_db = ioc_db
        self.config = config
        self.alertes = []

    def enrichir(self, evt: Dict) -> Dict:
        """Enrichit un événement avec la TIP."""
        ip = evt.get('ip')
        if ip and ip in self.ioc_db:
            evt['tip_match'] = self.ioc_db[ip]
            evt['tip_score'] = self.ioc_db[ip]['score']
        return evt

    def analyser_fenetre(self, fenetre: List[Dict], evt: Dict) -> List[Dict]:
        """Évalue les règles de corrélation sur la fenêtre."""
        nouvelles_alertes = []
        ip = evt.get('ip')

        # Règle 1 : Brute force
        echecs = [e for e in fenetre if e.get('action') == 'login_fail' and e.get('ip') == ip]
        if len(echecs) >= self.config['seuil_brute_force']:
            nouvelles_alertes.append({
                'regle': 'BRUTE_FORCE', 'ip': ip, 'severite': 'HAUTE',
                'count': len(echecs), 'timestamp': evt['timestamp']
            })

        # Règle 2 : IOC connu
        if evt.get('tip_score', 0) >= self.config['seuil_tip_score']:
            nouvelles_alertes.append({
                'regle': 'KNOWN_IOC', 'ip': ip, 'severite': 'CRITIQUE',
                'score': evt['tip_score'], 'tags': evt.get('tip_match', {}).get('tags', []),
                'timestamp': evt['timestamp']
            })

        # Règle 3 : Compromission (fail + success depuis même IP)
        if evt.get('action') == 'login_success':
            precédents_échecs = [e for e in fenetre 
                                  if e.get('action') == 'login_fail' and e.get('ip') == ip]
            if len(precédents_échecs) >= 3:
                nouvelles_alertes.append({
                    'regle': 'COMPROMISSION', 'ip': ip, 'severite': 'CRITIQUE',
                    'echecs': len(precédents_échecs), 'timestamp': evt['timestamp']
                })

        self.alertes.extend(nouvelles_alertes)
        return nouvelles_alertes

engine = DetectionEngine(IOC_DB, CONFIG)
print("Moteur de détection initialisé")
